const makeGraySvg = (svg: string) => {
    let s = svg;
    s = s.replace(/fill="(?!none)[^"]*"/g, 'fill="#4B4B4A"');
    s = s.replace(/stroke="(?!none)[^"]*"/g, 'stroke="#4B4B4A"');
    return s;
};

const guessSvgSize = (svg: string) => {
    const viewBoxMatch = svg.match(/viewBox="0 0 (\d+(?:\.\d+)?) (\d+(?:\.\d+)?)"/);
    if (viewBoxMatch) {
        const w = Number(viewBoxMatch[1]);
        const h = Number(viewBoxMatch[2]);
        const m = Math.max(w, h);
        if (Number.isFinite(m) && m > 0) return m;
    }

    const widthMatch = svg.match(/width="(\d+(?:\.\d+)?)"/);
    const heightMatch = svg.match(/height="(\d+(?:\.\d+)?)"/);
    if (widthMatch || heightMatch) {
        const w = widthMatch ? Number(widthMatch[1]) : NaN;
        const h = heightMatch ? Number(heightMatch[1]) : NaN;
        const m = Math.max(Number.isFinite(w) ? w : 0, Number.isFinite(h) ? h : 0);
        if (Number.isFinite(m) && m > 0) return m;
    }

    return 24;
};

const addGrayIconVariantsFromExistingIcons: () => void = () => {
    for (const key of Object.keys(Icons)) {
        if (key.startsWith('Colored')) continue;
        if (key.startsWith('Gray')) continue;

        const svg = Icons[key];
        if (typeof svg !== 'string') continue;

        const size = guessSvgSize(svg);
        const normalizedSize = size <= 18 ? 16 : size <= 28 ? 24 : 32;
        const targetPrefix = normalizedSize === 16 ? 'Gray_' : normalizedSize === 24 ? 'Gray24_' : 'Gray32_';
        const targetKey = `${targetPrefix}${key}`;

        Icons[targetKey] = svg;
    }
};

const addDerivedIconVariants: (sourcePrefix: string, targetPrefix: string) => void = (
    sourcePrefix: string,
    targetPrefix: string,
) => {
    for (const key of Object.keys(Icons)) {
        if (!key.startsWith(sourcePrefix)) continue;
        const suffix = key.slice(sourcePrefix.length);
        const targetKey = `${targetPrefix}${suffix}`;
        if (Object.prototype.hasOwnProperty.call(Icons, targetKey)) continue;
        const svg = Icons[key];
        if (typeof svg !== 'string') continue;
        Icons[targetKey] = makeGraySvg(svg);
    }
};

addGrayIconVariantsFromExistingIcons();
addDerivedIconVariants('Colored_', 'Gray_');
addDerivedIconVariants('Colored24_', 'Gray24_');
addDerivedIconVariants('Colored32_', 'Gray32_');
